using Microsoft.Build.Logging.StructuredLogger;
using System;

var build = BinaryLog.ReadBuild("/tmp/sv-52773544ec6b43d788656e1b2a77a796/build.binlog");
Console.WriteLine($"Build succeeded: {build.Succeeded}");
Console.WriteLine();

void Visit(BaseNode node)
{
    if (node is Error error)
    {
        var project = "";
        var parent = error.Parent;
        while (parent != null)
        {
            if (parent is Project p) { project = p.Name; break; }
            parent = (parent as TreeNode)?.Parent as BaseNode;
        }
        Console.WriteLine($"[ERROR in {project}] {error.Code}: {error.Text}");
        if (!string.IsNullOrEmpty(error.File))
            Console.WriteLine($"  File: {error.File}({error.LineNumber},{error.ColumnNumber})");
        Console.WriteLine();
    }
    if (node is TreeNode treeNode)
    {
        foreach (var child in treeNode.Children)
        {
            if (child is BaseNode bn) Visit(bn);
        }
    }
}
Visit(build);
