        Console.WriteLine($"  MSG: {msg.Text.Substring(0, Math.Min(200, msg.Text.Length))}");
    }
    if (node is TreeNode treeNode)
    {
        foreach (var child in treeNode.Children)
        {
            if (child is BaseNode bn) VisitAll(bn);
        }
    }
