using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Collections.Generic;

var build = BinaryLog.ReadBuild("/tmp/sv-52773544ec6b43d788656e1b2a77a796/build.binlog");

// Check build-level result for each top-level project build
void Visit(BaseNode node, int depth)
{
    if (node is Project p && depth <= 3)
    {
        // Check if the project has any Error children (recursive)
        var hasError = HasError(p);
        var targets = new List<string>();
        foreach (var child in p.Children)
        {
            if (child is Target t && !t.Name.StartsWith("_"))
                targets.Add(t.Name);
        }
        Console.WriteLine($"{"".PadLeft(depth*2)}Project: {p.Name} HasErrors:{hasError}");
    }
    if (node is TreeNode treeNode)
    {
        foreach (var child in treeNode.Children)
        {
            if (child is BaseNode bn) Visit(bn, depth + 1);
        }
    }
}

bool HasError(BaseNode node)
{
    if (node is Error) return true;
    if (node is TreeNode tn)
    {
        foreach (var child in tn.Children)
            if (child is BaseNode bn && HasError(bn)) return true;
    }
    return false;
}

Visit(build, 0);
